import React from 'react';
import { Card, CardContent, Typography, Stack, Chip, CircularProgress } from '@mui/material';
import response from './response.json';

interface Task {
  task: string;
  priority: string;
  completed: boolean;
}

interface TaskManagerData {
  todayTasks: Task[];
  completionProgress: number;
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const taskManagerData = response.data as TaskManagerData;
  const metaData = response.meta as MetaData;

  const { todayTasks, completionProgress } = taskManagerData;
  const { primaryColor, accentColor } = metaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: primaryColor }}>
            Today's Tasks
          </Typography>

          <Stack direction="column" spacing={1}>
            {todayTasks.map((task, index) => (
              <Stack key={index} direction="row" spacing={1} alignItems="center">
                <Chip
                  label={task.priority}
                  sx={{
                    bgcolor: task.completed ? '#10B981' : accentColor,
                    color: '#FFFFFF',
                    fontSize: '10px',
                    height: '20px',
                  }}
                />
                <Typography
                  variant="body2"
                  sx={{ color: task.completed ? '#6B7280' : '#F8FAFC', textDecoration: task.completed ? 'line-through' : 'none' }}
                >
                  {task.task}
                </Typography>
              </Stack>
            ))}
          </Stack>

          <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mt: 2 }}>
            <Typography variant="body2" color="text.secondary">
              Progress
            </Typography>
            <CircularProgress
              variant="determinate"
              value={completionProgress}
              size={36}
              sx={{
                color: primaryColor,
                '& .MuiCircularProgress-circle': {
                  strokeLinecap: 'round',
                },
              }}
            />
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
